package com.google.gson.internal;

import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.internal.bind.TypeAdapters;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class StreamsTest {

  @Test
  void write_delegatesToTypeAdaptersJsonElementWrite() throws IOException {
    JsonElement element = mock(JsonElement.class);
    JsonWriter writer = mock(JsonWriter.class);

    try (MockedStatic<TypeAdapters> typeAdaptersStatic = Mockito.mockStatic(TypeAdapters.class)) {
      var jsonElementAdapter = mock(TypeAdapters.JSON_ELEMENT.getClass());
      // We need to mock TypeAdapters.JSON_ELEMENT.write(writer, element)
      // But JSON_ELEMENT is a static final field of some adapter type, so we mock the static field's write method by spying on it

      // Because JSON_ELEMENT is a static final field, we cannot mock it directly.
      // Instead, we spy on it and verify the call.

      // Spy on JSON_ELEMENT adapter
      var jsonElementAdapterSpy = spy(TypeAdapters.JSON_ELEMENT);

      // Use reflection to replace the JSON_ELEMENT field with spy temporarily
      var field = TypeAdapters.class.getDeclaredField("JSON_ELEMENT");
      field.setAccessible(true);
      var original = field.get(null);
      field.set(null, jsonElementAdapterSpy);

      try {
        Streams.write(element, writer);
        verify(jsonElementAdapterSpy).write(writer, element);
      } finally {
        // Restore original field value
        field.set(null, original);
      }
    } catch (NoSuchFieldException | IllegalAccessException e) {
      throw new RuntimeException(e);
    }
  }
}
